INSERT INTO public.pe_narratives (pe_id, fiscal_year, mission_description, justification, accomplishments, planned_program, performance_metrics, other_program_funding, raw_text, content_hash, section_hashes, source_pdf, source_page, ingested_at) VALUES ($$0401115F$$, 2026, $$The C-130H is a medium sized tactical transport aircraft providing multi-purpose theater support throughout the globe. The C-130H fleet supports several diverse Air
Force roles, including but not limited to tactical and inter-theater airlift and airdrop support, Arctic resupply, special operations support, aeromedical evacuation, aerial
spraying, firefighting duties, and natural disaster and humanitarian relief missions.

 Previous funding provides weapon system modifications and upgrades to meet USAF mission requirements for the LC/C-130H fleets.

 C-130H AMP Increment 2 includes digital avionics upgrades (e.g. Flight Management System, improved navigation), cockpit modernization (e.g. digital flight displays)
 and resolves select obsolescence and Diminishing Manufacturing Source (DMS) issues. RDT&E efforts cover software development, design, integration, developmental
 and operational test, studies and risk reduction efforts, trial kit buy and installation, technical order development validation and verification, spares and peculiar support
 equipment in support of trial kit installs, Systems Integration Laboratory (SIL) development, type 1 training and C-130H aircrew and maintenance training systems and
 courseware development efforts, program office support and other efforts necessary to fulfill program requirements. Project 672030, MUOS/SATURN, is now included in
 project 675250, AMP Increment 2. The MUOS/SATURN radio addresses future DMS/integration issues and incorporates MUOS/SATURN capabilities.

 Milestone C (MS C) is now planned for June 2026. This change is due to flight testing taking longer than planned due to the development, installation, and testing of
 corrections required prior to MS C.

 This funding includes Rapid Global Mobility (RGM) platform related activities including but not limited to prototyping, capability development, process activities, planning
 analysis and systems engineering activities.

 This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs
